#include <stdio.h>

int main() {
    // Static array declaration
    int arr[5] = {10, 20, 30, 40, 50};

    // Accessing elements using index
    printf("Element at index 0: %d\n", arr[0]);
    printf("Element at index 3: %d\n", arr[3]);

    // Array traversal
    for(int i = 0; i < 5; i++) {
        printf("arr[%d] = %d\n", i, arr[i]);
    }

    // Calculate address of element
    int base = (int)&arr[0];
    int elemSize = sizeof(int);
    printf("Address of arr[2]: %d\n", base + (2 * elemSize));

    return 0;
}

#include <stdio.h>

// Function to calculate address in row-major order
int getAddress(int base, int row, int col, int ncols, int elemSize) {
    // Address = Base + ((row * ncols) + col) * elementSize
    return base + ((row * ncols) + col) * elemSize;
}

int main() {
    // Declare a 3x4 matrix (3 rows, 4 columns)
    int matrix[3][4];
    int baseAddress = 1000;
    int elementSize = sizeof(int);  // 4 bytes

    // Initialize matrix with values
    int count = 1;
    for(int i = 0; i < 3; i++) {
        for(int j = 0; j < 4; j++) {
            matrix[i][j] = count++;
        }
    }

    // Calculate address of matrix[2][3]
    int addr = getAddress(baseAddress, 2, 3, 4, elementSize);
    printf("Address of matrix[2][3]: %d\n", addr);
    printf("Value at matrix[2][3]: %d\n", matrix[2][3]);

    // In row-major: index = (2 * 4) + 3 = 11
    // Address = 1000 + (11 * 4) = 1000 + 44 = 1044

    return 0;
}

#include <stdio.h>

#define MAX_DEGREE 100

// Function to add two polynomials
void addPolynomials(int poly1[], int poly2[], int result[], int maxDegree) {
    for(int i = 0; i <= maxDegree; i++) {
        result[i] = poly1[i] + poly2[i];
    }
}

// Function to display polynomial
void displayPolynomial(int poly[], int degree) {
    int first = 1;
    for(int i = degree; i >= 0; i--) {
        if(poly[i] != 0) {
            if(!first && poly[i] > 0) printf(" + ");
            if(poly[i] < 0) printf(" - ");
            printf("%d", abs(poly[i]));
            if(i > 1) printf("x^%d", i);
            else if(i == 1) printf("x");
            first = 0;
        }
    }
    printf("\n");
}

int main() {
    // Polynomial: 3x^2 + 2x + 5
    int poly1[MAX_DEGREE + 1] = {0};
    poly1[0] = 5;   // constant
    poly1[1] = 2;   // x^1
    poly1[2] = 3;   // x^2

    // Polynomial: 2x^3 + x + 7
    int poly2[MAX_DEGREE + 1] = {0};
    poly2[0] = 7;   // constant
    poly2[1] = 1;   // x^1
    poly2[3] = 2;   // x^3

    int result[MAX_DEGREE + 1] = {0};

    printf("Polynomial 1: ");
    displayPolynomial(poly1, 3);

    printf("Polynomial 2: ");
    displayPolynomial(poly2, 3);

    addPolynomials(poly1, poly2, result, MAX_DEGREE);

    printf("Result: ");
    displayPolynomial(result, 3);
    // Output: 2x^3 + 3x^2 + 3x + 12

    return 0;
}
